INSERT INTO `pages` (`id`, `name`, `slug`, `content`, `created_at`, `updated_at`) VALUES
(1, 'About Us', 'about-us', '<p style=\"margin-right: 0px; margin-bottom: 34px; margin-left: 0px; color: rgb(37, 37, 37); font-family: Lora, serif; font-size: 19px; letter-spacing: -0.2px;\">The About Us page of your website is an essential source of information for anyone who wants to know more about your business.<span style=\"letter-spacing: -0.2px;\">It is where you showcase your history, the unique value of your work, your mission and vision, and the&nbsp;</span><font color=\"rgba(0, 0, 0, 0)\"><span style=\"letter-spacing: -0.2px; transition-duration: 0.2s; border-bottom: 2.5px solid rgb(113, 194, 27);\">audiences you serve</span></font><span style=\"letter-spacing: -0.2px;\">.</span></p><p style=\"margin-right: 0px; margin-bottom: 34px; margin-left: 0px; color: rgb(37, 37, 37); font-family: Lora, serif; font-size: 19px; letter-spacing: -0.2px;\"><span style=\"letter-spacing: -0.2px;\">Together,&nbsp;</span><font color=\"rgba(0, 0, 0, 0)\"><span style=\"letter-spacing: -0.2px; transition-duration: 0.2s; border-bottom: 2.5px solid rgb(113, 194, 27);\">the design</span></font><span style=\"letter-spacing: -0.2px;\">, written content, and visual elements of an About Us page tell an important story about who you are and what matters to you.</span></p><h2 style=\"margin: 60px 0px 20px; font-family: Inter, sans-serif; font-weight: 700; color: rgb(37, 37, 37); font-size: 32px; overflow-wrap: break-word; letter-spacing: 0.1px;\">What Makes A Great About Us Page?</h2><p style=\"margin-right: 0px; margin-bottom: 34px; margin-left: 0px; color: rgb(37, 37, 37); font-family: Lora, serif; font-size: 19px; letter-spacing: -0.2px;\">There is no definitive template for creating a great About Us page.</p><p style=\"margin-right: 0px; margin-bottom: 34px; margin-left: 0px; color: rgb(37, 37, 37); font-family: Lora, serif; font-size: 19px; letter-spacing: -0.2px;\">However, I found four key components to making a compelling narrative with your&nbsp;<a href=\"https://www.searchenginejournal.com/story-types-brands-marketers/297929/\" style=\"color: inherit; transition: 0.2s; border-bottom: 2.5px solid rgb(113, 194, 27);\">brand story</a>.</p><p style=\"margin-right: 0px; margin-bottom: 34px; margin-left: 0px; color: rgb(37, 37, 37); font-family: Lora, serif; font-size: 19px; letter-spacing: -0.2px;\"><span style=\"letter-spacing: -0.2px;\">How can you make the most of this integral part of your marketing strategy?</span></p><p style=\"margin-right: 0px; margin-bottom: 34px; margin-left: 0px; color: rgb(37, 37, 37); font-family: Lora, serif; font-size: 19px; letter-spacing: -0.2px;\">In this article, discover what makes an exceptional About Us page and find 25 examples to inspire your own page design and content.</p>', '2025-11-04 01:56:52', '2025-11-06 01:23:19'),
(2, 'Contact Us Pages', 'contact-us-pages', '<div><p data-start=\"0\" data-end=\"248\">It is a long established fact that a reader will be distracted by the readable content of a page when looking at its layout. The point of using Lorem Ipsum is that it has a more-or-less normal distribution of letters, as opposed to using Content.</p>\r\n<p data-start=\"250\" data-end=\"346\" data-is-last-node=\"\" data-is-only-node=\"\">Indore,&nbsp;Madhya Pradesh<br data-start=\"265\" data-end=\"268\">102 Orbit Mall, Vijay Nagar, 452001<br data-start=\"314\" data-end=\"317\">\r\n(+91) 9977996955&nbsp;<br data-start=\"331\" data-end=\"334\">\r\n<a href=\"mailto:uday.thakur626@gmail.com\">thakuruday95@gmail.com</a></p></div>', '2025-11-04 01:57:22', '2025-11-11 02:42:11'),
(3, 'Legal Department', 'legal-department', '<p>Legal Department for fraud or any dispute.</p>', '2025-11-04 01:58:23', '2025-11-04 01:58:23'),
(4, 'Carrier Form', 'carrier-form', '<h2 class=\"intro-heading text-uppercase mb-2\" style=\"line-height: 1.5rem; color: rgb(0, 0, 0); font-size: 0.875rem; letter-spacing: 0.15em; font-family: Basis-bold;\">Join us</h2><h3 class=\"intro-description textasset-light-background\" style=\"margin-bottom: 2rem; line-height: 2.4rem; color: rgb(0, 0, 0); font-size: 2rem; font-family: Houschka-medium;\">Shape the future of technology<p></p><div class=\"intro-text rte-links-div textasset-light-background\" style=\"font-size: 1.125rem; line-height: 2rem; letter-spacing: 0.03125rem; font-family: Basis-regular;\"><p style=\"margin-bottom: 0px; line-height: 1.8rem; font-size: 1.125rem; letter-spacing: 0.03125rem;\">As a global company with unparalleled scale, a track record of pioneering innovation, and a huge and influential client base, we offer associates a chance to drive change and improve the lives of millions of people around the world.</p><p style=\"margin-bottom: 0px; line-height: 1.8rem; font-size: 1.125rem; letter-spacing: 0.03125rem;\"><br></p></div></h3><h2 class=\"section-title\" style=\"margin-bottom: 2rem; line-height: 2.5rem; color: rgb(33, 37, 41); font-size: 2.5rem; font-family: Houschka-medium;\">Seize your future. Join us to dream big.</h2><h3 class=\"intro-description textasset-light-background\" style=\"margin-bottom: 2rem; line-height: 2.4rem; color: rgb(0, 0, 0); font-size: 2rem; font-family: Houschka-medium;\"><div class=\"intro-text rte-links-div textasset-light-background\" style=\"font-size: 1.125rem; line-height: 2rem; letter-spacing: 0.03125rem; font-family: Basis-regular;\"><p class=\"story-description\" style=\"margin-bottom: 2rem; font-size: 1.125rem; line-height: 2rem; letter-spacing: 0.03125rem; opacity: 0.9;\">Our people are our greatest asset. We are committed in supporting them to change the world and create a better future for everyone. We believe in developing holistic careers through providing aspirational opportunities and support to continually learn and grow into the best version of themselves.</p></div></h3><h2 class=\"intro-description textasset-light-background\" style=\"margin-bottom: 2rem; line-height: 2.4rem; color: rgb(0, 0, 0); font-family: Houschka-medium;\">Be the next architect of digital India</h2><h3 class=\"intro-description textasset-light-background\" style=\"margin-bottom: 2rem; line-height: 2.4rem; color: rgb(0, 0, 0); font-size: 2rem; font-family: Houschka-medium;\"><div class=\"intro-text rte-links-div textasset-light-background\" style=\"font-size: 1.125rem; line-height: 2rem; letter-spacing: 0.03125rem; font-family: Basis-regular;\"><div class=\"intro-text rte-links-div textasset-light-background\" style=\"font-size: 1.125rem; line-height: 2rem; letter-spacing: 0.03125rem;\"><p style=\"margin-bottom: 0px; line-height: 1.8rem; font-size: 1.125rem; letter-spacing: 0.03125rem;\">TCS impacts the lives of nearly 7 out of 10 Indians — enabling access to essential services, unlocking opportunities, and making Digital India a reality for all. This is more than transformation – it’s technology in the service of people, a story of enduring commitment to a nation, and a promise to every citizen. Watch how TCS is Accelerating India’s digital journey, one innovation at a time.</p></div></div></h3>', '2025-11-04 01:58:55', '2025-11-06 01:20:40'),
(5, 'Human Resources (H.R) Department Contact', 'human-department-contact', '<p>H.R department for any inquery generate.</p><p>Human resources (HR) is the set of people who make up the workforce of an organization, business sector, industry, or economy.[1][2] A narrower concept is human capital, the knowledge and skills which the individuals command</p><p>Distinction to human resource management</p><p>Main article: Human resource management</p><p>In vernacular usage, \"human resources\" or \"human resource\" can refer to the human resources department (HR department)[4] of an organization, which performs human resource management, overseeing various aspects of employment, such as compliance with labor law and employment standards, interviewing and selection, performance management, administration of employee benefits, organizing of employee files with the required documents for future reference, and some aspects of recruitment (also known as talent acquisition), talent management, staff wellbeing, and employee offboarding.[5] They serve as the link between an organization\'s management and its employees.</p><p><span style=\"font-size: 1rem;\">The duties include planning, recruitment and selection process, posting job ads, evaluating the performance of employees, organizing resumes and job applications, scheduling interviews and assisting in the process and ensuring background checks. Another duty is payroll and benefits administration, which deals with ensuring vacation and sick time are accounted for, reviewing payroll, and participating in benefits tasks, such as claim resolutions, reconciling benefits statements, and approving invoices for payment.[6] Human resources also coordinates employee relations activities and programs, including employee counseling.</span></p><p style=\"margin: 0.5em 0px 1em; color: rgb(32, 33, 34); font-family: sans-serif;\">A human resources manager can have various functions in a&nbsp;<a href=\"https://en.wikipedia.org/wiki/Company\" title=\"Company\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\">company</a>, including to:<sup id=\"cite_ref-14\" class=\"reference\" style=\"line-height: 1; unicode-bidi: isolate; text-wrap-mode: nowrap; font-size: 12.8px;\"><a href=\"https://en.wikipedia.org/wiki/Human_resources#cite_note-14\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\"><span class=\"cite-bracket\" style=\"pointer-events: none;\">[</span>14<span class=\"cite-bracket\" style=\"pointer-events: none;\">]</span></a></sup><sup id=\"cite_ref-15\" class=\"reference\" style=\"line-height: 1; unicode-bidi: isolate; text-wrap-mode: nowrap; font-size: 12.8px;\"><a href=\"https://en.wikipedia.org/wiki/Human_resources#cite_note-15\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\"><span class=\"cite-bracket\" style=\"pointer-events: none;\">[</span>15<span class=\"cite-bracket\" style=\"pointer-events: none;\">]</span></a></sup><sup id=\"cite_ref-16\" class=\"reference\" style=\"line-height: 1; unicode-bidi: isolate; text-wrap-mode: nowrap; font-size: 12.8px;\"><a href=\"https://en.wikipedia.org/wiki/Human_resources#cite_note-16\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\"><span class=\"cite-bracket\" style=\"pointer-events: none;\">[</span>16<span class=\"cite-bracket\" style=\"pointer-events: none;\">]</span></a></sup><sup id=\"cite_ref-17\" class=\"reference\" style=\"line-height: 1; unicode-bidi: isolate; text-wrap-mode: nowrap; font-size: 12.8px;\"><a href=\"https://en.wikipedia.org/wiki/Human_resources#cite_note-17\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\"><span class=\"cite-bracket\" style=\"pointer-events: none;\">[</span>17<span class=\"cite-bracket\" style=\"pointer-events: none;\">]</span></a></sup><sup id=\"cite_ref-18\" class=\"reference\" style=\"line-height: 1; unicode-bidi: isolate; text-wrap-mode: nowrap; font-size: 12.8px;\"><a href=\"https://en.wikipedia.org/wiki/Human_resources#cite_note-18\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\"><span class=\"cite-bracket\" style=\"pointer-events: none;\">[</span>18<span class=\"cite-bracket\" style=\"pointer-events: none;\">]</span></a></sup></p><ul style=\"margin: -0.5em 0px 0px 1.6em; margin-inline: 1.6em 0px; padding: 0px; color: rgb(32, 33, 34); font-family: sans-serif;\"><li style=\"margin-bottom: 0.1em;\">Determine the needs of the staff/personnel</li><li style=\"margin-bottom: 0.1em;\"><a href=\"https://en.wikipedia.org/wiki/Human_resource_accounting\" title=\"Human resource accounting\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\">Human resource accounting</a>, determine whether to use temporary staff or hire employees to fill these needs</li><li style=\"margin-bottom: 0.1em;\">Recruit and/or interview hires</li><li style=\"margin-bottom: 0.1em;\">Prepare employee records and personal policies</li><li style=\"margin-bottom: 0.1em;\">Manage employee payroll, benefits, and&nbsp;<a href=\"https://en.wikipedia.org/wiki/Compensation_and_benefits\" title=\"Compensation and benefits\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\">compensation</a></li><li style=\"margin-bottom: 0.1em;\">Manage employee relations, prepare remote work and hybrid work policy</li><li style=\"margin-bottom: 0.1em;\"><a href=\"https://en.wikipedia.org/wiki/Employee_retention\" title=\"Employee retention\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\">Employee retention</a>,&nbsp;<a href=\"https://en.wikipedia.org/wiki/Talent_management\" title=\"Talent management\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\">talent management</a></li><li style=\"margin-bottom: 0.1em;\">Deal with performance issues,&nbsp;<a href=\"https://en.wikipedia.org/wiki/Motivation\" title=\"Motivation\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\">motivate</a>&nbsp;employees, monitor staff well-being</li><li style=\"margin-bottom: 0.1em;\">Mediate disputes, Establish&nbsp;<a href=\"https://en.wikipedia.org/wiki/Organizational_culture\" title=\"Organizational culture\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\">organizational culture</a>&nbsp;in the organization</li><li style=\"margin-bottom: 0.1em;\">Reduce&nbsp;<a href=\"https://en.wikipedia.org/wiki/Workplace_politics\" title=\"Workplace politics\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\">workplace politics</a>, ensure equal opportunities, reduce&nbsp;<a href=\"https://en.wikipedia.org/wiki/Discrimination\" title=\"Discrimination\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\">discrimination</a></li><li style=\"margin-bottom: 0.1em;\">Ensure that human resources practices conform to various regulations and&nbsp;<a href=\"https://en.wikipedia.org/wiki/Human_resource_metrics\" title=\"Human resource metrics\" style=\"color: rgb(51, 102, 204); background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-radius: 2px; overflow-wrap: break-word;\">human resource metrics</a></li><li style=\"margin-bottom: 0.1em;\">Apply HR software to improve HR effectivity.</li><li style=\"margin-bottom: 0.1em;\">Human resources can be evaluated empirically using various frameworks such as Stamina Model</li></ul>', '2025-11-04 02:00:07', '2025-11-10 03:35:25'),
(6, 'SEO Services', 'seo-services', '<p><b><u>SEO Services</u></b> for top up ranking on webstie traffic search.</p>', '2025-11-04 02:11:01', '2025-11-10 00:52:10');
