INSERT INTO `products` (`id`, `title`, `slug`, `description`, `short_description`, `shipping_returns`, `related_products`, `price`, `compare_price`, `category_id`, `sub_category_id`, `brand_id`, `is_featured`, `sku`, `barcode`, `track_qty`, `qty`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Hyundai Creta', 'hyundai-creta', '<p>Hyundai Creta Price - Images, Colours &amp; Reviews</p><h2 class=\"\" style=\"line-height: 1.4; margin-right: 0px; margin-bottom: 8px; margin-left: 0px; padding: 0px; color: rgb(36, 39, 44); font-size: 23px; font-family: roboto, sans-serif, Arial;\">Hyundai Creta latest updates</h2><div class=\"gs_readmore model-highlight marginBottom20 latestUpdate   loaded viewless\" style=\"margin-bottom: 20px; clear: both; overflow: hidden; position: relative; font-size: 15px; line-height: 1.6; color: rgba(36, 39, 44, 0.7); font-family: roboto, sans-serif, Arial; height: auto;\"><ul style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px 0px 0px 20px;\"><li dir=\"ltr\" style=\"list-style: disc;\"><p style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; line-height: 1.6;\"><span style=\"font-weight: 600;\">August 13, 2025:&nbsp;</span>Kerala customers buying the Hyundai Creta this Onam season&nbsp;is being offered with a scrappage discount of Rs 5,000.<span style=\"font-weight: 600;\"></span></p></li><li dir=\"ltr\" style=\"list-style: disc;\"><p style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; line-height: 1.6;\"><span style=\"font-weight: 600;\">August 11, 2025:&nbsp;</span>The total sales of the Hyundai Creta nameplate stood at 16,898&nbsp;units in August 2025. Its sales figures include the Hyundai Creta Electric and Hyundai Creta N Line.<span style=\"font-weight: 600;\"></span></p></li><li dir=\"ltr\" style=\"list-style: disc;\"><p style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; line-height: 1.6;\"><span style=\"font-weight: 600;\">August 6, 2025:&nbsp;</span>The Hyundai Creta is being offered with a scrappage discount of Rs 5,000 this August.</p></li><li dir=\"ltr\" style=\"list-style: disc;\"><p style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; line-height: 1.6;\"><span style=\"font-weight: 600;\">July 21, 2025:&nbsp;</span>The Hyundai Creta has turned 10 years old in India. It first went on sale in 2015 and is now in its second-generation. Hyundai sold over 12 lakh units of the Creta in India since its inception.</p></li><li dir=\"ltr\" style=\"list-style: disc;\"><p style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; line-height: 1.6;\"><span style=\"font-weight: 600;\">July 2, 2025:&nbsp;</span>The Hyundai Creta has become the bestselling car in June 2025 with total sales of 15,786 units.</p></li><li dir=\"ltr\" style=\"list-style: disc;\"><p style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; line-height: 1.6;\"><span style=\"font-weight: 600;\">June 25, 2025:&nbsp;</span>Hyundai has organised a Monsoon Service Camp till July 20, which will include free vehicle inspection and special discounts in servicing and extended warranty costs for Creta owners.&nbsp;</p></li></ul></div>', NULL, NULL, NULL, 1500000.00, 1600000.00, 3, 13, 9, 'Yes', 'sku-01', 'barcode-01', 'Yes', 5, 0, '2025-08-18 05:50:00', '2025-08-28 06:00:37'),
(2, 'Hyundai i20', 'hyundai-i20', '<p style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 12px 0px 0px; color: rgb(51, 51, 51); font-family: LatoGoogle, Lato, LatoWeb, sans-serif;\"><span style=\"margin: 0px; padding: 0px; color: rgb(0, 0, 0);\">Positives:</span></p><ul style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 16px; padding: 12px 0px 0px; list-style-position: initial; list-style-image: initial; color: rgb(51, 51, 51); font-family: LatoGoogle, Lato, LatoWeb, sans-serif;\"><li style=\"margin: 0px 0px 12px; padding: 0px;\">The 114.7Nm 1.2-litre four-cylinder petrol engine makes 87bhp with the iVT (Intelligent Variable Transmission) and 82bhp with the five-speed manual transmission.</li><li style=\"margin: 0px 0px 12px; padding: 0px;\">It gets two drive modes that enhance the driving experience - normal mode and Sports mode.</li><li style=\"margin: 0px 0px 12px; padding: 0px;\">The light steering makes it easy to drive within the tight confines of the city.</li><li style=\"margin: 0px 0px 12px; padding: 0px;\">The i20’s ride quality at higher speeds is flat and absorbent.</li><li style=\"margin: 0px; padding: 0px;\">With the quick steering response, this Hyundai hatchback changes directions rapidly.</li></ul><p style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 12px 0px 0px; color: rgb(51, 51, 51); font-family: LatoGoogle, Lato, LatoWeb, sans-serif;\"><span style=\"margin: 0px; padding: 0px; color: rgb(0, 0, 0);\">Negatives:</span></p><ul style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 16px; padding: 12px 0px 0px; list-style-position: initial; list-style-image: initial; color: rgb(51, 51, 51); font-family: LatoGoogle, Lato, LatoWeb, sans-serif;\"><li style=\"margin: 0px 0px 12px; padding: 0px;\">Since the low-speed ride is a little hard, you can feel the ruts and bumps filter into the cabin.</li><li style=\"margin: 0px; padding: 0px;\">As the steering lacks response around the centre position and is oversensitive at higher speeds, it dampens the driver experience.</li></ul>', NULL, NULL, NULL, 1000000.00, 1200000.00, 3, 13, 13, '', 'sku-02', 'barcode-02', 'Yes', 5, 0, '2025-08-18 05:53:37', '2025-08-28 06:00:29'),
(3, 'Tata Nexon', 'tata-nexon', '<h2 class=\"wp-block-heading\" style=\"margin: 0.83em 0px 0.5em; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; font-size: 1.953em; line-height: 1.35; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(33, 33, 33); text-rendering: optimizelegibility;\">Tata Nexon Gets New Base Model</h2><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; font-size: 18px; line-height: inherit; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><a href=\"https://www.carblogindia.com/tata-nexon-altroz-nano-safety/\" target=\"_blank\" rel=\"noopener\" title=\"\" style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; font-size: inherit; line-height: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(247, 13, 40);\">Tata Motors</a>&nbsp;is calling it the Smart (O) trim. It has a price tag of an enticing Rs 7.99 lakh, ex-showroom. Note that the previous base model (Smart) had a retail sticker of Rs 8.15 lakh, ex-showroom. It is not clear whether the Indian auto giant will continue to offer that trim or will this new version replace it. The mid-level variant goes by Pure in Tata Motors’ parlance. That has a starting price of Rs 9.80 lakh, ex-showroom. Hence, there is a difference of a whopping Rs 1.81 lakh, ex-showroom between the two. Despite being the base model, the Smart (O) gets useful amenities like:</p><div class=\"google-anno-skip google-anno-sc\" tabindex=\"0\" role=\"link\" aria-label=\"Nearby car dealerships\" data-google-vignette=\"false\" data-google-interstitial=\"false\" style=\"color-scheme: initial !important; forced-color-adjust: initial !important; mask: initial !important; math-depth: initial !important; position: initial !important; position-anchor: initial !important; text-size-adjust: initial !important; appearance: initial !important; color: rgb(255, 255, 255) !important; direction: inherit !important; font: initial !important; font-palette: initial !important; font-synthesis: initial !important; position-area: initial !important; text-orientation: inherit !important; text-rendering: initial !important; text-spacing-trim: initial !important; -webkit-font-smoothing: initial !important; -webkit-locale: initial !important; -webkit-text-orientation: initial !important; -webkit-writing-mode: initial !important; writing-mode: inherit !important; zoom: initial !important; accent-color: initial !important; place-content: initial !important; place-items: initial !important; place-self: initial !important; alignment-baseline: initial !important; anchor-name: initial !important; anchor-scope: initial !important; animation-composition: initial !important; animation: initial !important; app-region: initial !impo