INSERT INTO `products` (`id`, `title`, `slug`, `description`, `short_description`, `shipping_returns`, `related_products`, `price`, `compare_price`, `category_id`, `sub_category_id`, `brand_id`, `is_featured`, `sku`, `barcode`, `track_qty`, `qty`, `status`, `created_at`, `updated_at`) VALUES
(4, 'Motorola Moto G85', 'motorola-moto-g85', '<div class=\"mb-5 text-2xl font-bold\" style=\"border: 0px solid rgb(229, 231, 235); --tw-border-spacing-x: 0; --tw-border-spacing-y: 0; --tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-gradient-from-position: ; --tw-gradient-via-position: ; --tw-gradient-to-position: ; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgba(59,130,246,.5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdrop-invert: ; --tw-backdrop-opacity: ; --tw-backdrop-saturate: ; --tw-backdrop-sepia: ; --tw-contain-size: ; --tw-contain-layout: ; --tw-contain-paint: ; --tw-contain-style: ; margin-bottom: 1.25rem; font-size: 1.5rem; line-height: 2rem; font-weight: 700; color: rgb(58, 58, 58); font-family: __Poppins_51684b, __Poppins_Fallback_51684b; text-align: justify;\">Motorola Moto G85 5G (256GB,12GB) Urban Gray</div><p style=\"border: 0px solid rgb(229, 231, 235); --tw-border-spacing-x: 0; --tw-border-spacing-y: 0; --tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-gradient-from-position: ; --tw-gradient-via-position: ; --tw-gradient-to-position: ; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgba(59,130,246,.5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdrop-invert: ; --tw-backdrop-opacity: ; --tw-backdrop-saturate: ; --tw-backdrop-sepia: ; --tw-contain-size: ; --tw-contain-layout: ; --tw-contain-paint: ; --tw-contain-style: ; margin-right: 0px; margin-bottom: 1.25rem; margin-left: 0px; color: rgb(58, 58, 58); font-family: __Poppins_51684b, __Poppins_Fallback_51684b; font-size: 14px; text-align: justify;\">The Motorola Moto G85 5G is a high-performance smartphone designed for speed and style. It features a 6.67-inch P-OLED display with 1 billion colors, a 120Hz refresh rate, and an impressive peak brightness of 1600 nits, delivering vibrant visuals. Powered by the Qualcomm Snapdragon 6s Gen 3 chipset and running Android 14, the device offers smooth multitasking with up to 256GB storage and 12GB RAM. Its dual-camera setup includes a 50MP main camera with OIS and an 8MP ultrawide lens, while the 32MP selfie camera ensures sharp, detailed shots. With a water-repellent design, Gorilla Glass 5 protection, 5G connectivity, and a 5000mAh battery, the Moto G85 5G is built for modern mobile experiences.</p>', NULL, NULL, NULL, 7500.00, 8000.00, 1, 14, 8, 'Yes', 'sku-04', 'barcode-04', 'Yes', 2, 1, '2025-08-18 05:59:40', '2026-02-26 08:15:49'),
(5, 'iPhone 16', 'iphone-16', '<p><span style=\"color: rgb(18, 18, 18); letter-spacing: 0.02em; font-family: &quot;SF Pro Text&quot;, -apple-system, BlinkMacSystemFont; font-size: 1rem;\">iPhone 16. Built for Apple Intelligence. Featuring Camera Control. 48MP Fusion camera. Five vibrant colours. And A18 chip.</span></p><div class=\"transparent_2 features js-features\" style=\"box-sizing: inherit; margin: 0px 0px 56px; padding: 0px; width: 1220px; display: flex; color: rgba(18, 18, 18, 0.75); font-family: &quot;SF Pro Text&quot;, -apple-system, BlinkMacSystemFont; letter-spacing: 0.6px;\"><div class=\"metafieldLabel collapseTheTd2\" style=\"box-sizing: inherit; margin: 0px; padding: 0px 162px 0px 0px; font-weight: 600; vertical-align: top; width: 488px; font-size: 24px; line-height: 30px; color: rgb(18, 18, 18);\">Features</div><div class=\"collapseTheTd2 overviewVal js-features-value\" style=\"box-sizing: inherit; margin: 0px; padding: 0px; vertical-align: top; color: rgb(18, 18, 18); line-height: 22px; letter-spacing: 0.02em; width: 732px;\"><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 0px; margin-left: 18px; padding: 0px;\"><li style=\"box-sizing: inherit; margin-top: 0px; margin-right: 0px; margin-bottom: 4px !important; margin-left: 0px; padding: 0px;\">BUILT FOR APPLE INTELLIGENCE — Apple Intelligence helps you write, express yourself and get things done effortlessly. With groundbreaking privacy protections, it gives you peace of mind that no one else can access your data — not even Apple.</li><li style=\"box-sizing: inherit; margin-top: 0px; margin-right: 0px; margin-bottom: 4px !important; margin-left: 0px; padding: 0px;\">TAKE TOTAL CAMERA CONTROL — Camera Control gives you an easier way to quickly access camera tools, like zoom or depth of field, so you can take the perfect shot in record time.</li><li style=\"box-sizing: inherit; margin-top: 0px; margin-right: 0px; margin-bottom: 4px !important; margin-left: 0px; padding: 0px;\">GET FURTHER AND CLOSER — The improved Ultra Wide camera with autofocus lets you take incredibly detailed macro photos and videos. Use the 48MP Fusion camera for stunning high-resolution images, and zoom in with the 2x optical-quality Telephoto.</li><li style=\"box-sizing: inherit; margin-top: 0px; margin-right: 0px; margin-bottom: 4px !important; margin-left: 0px; padding: 0px;\">PHOTOGRAPHIC STYLES — The latest-generation Photographic Styles give you greater creative flexibility, so you can make every photo even more you. And you can reverse any of those styles anytime you want.</li><li style=\"box-sizing: inherit; margin-top: 0px; margin-right: 0px; margin-bottom: 4px !important; margin-left: 0px; padding: 0px;\">SUPER-SMART A18 CHIP — A18 jumps two generations ahead of the A16 Bionic chip in iPhone 15. It enables Apple Intelligence, powers advanced photo and video features, and supports console-level gaming, with exceptional power efficiency.</li><li style=\"box-sizing: inherit; margin-top: 0px; margin-right: 0px; margin-bottom: 4px !important; margin-left: 0px; padding: 0px;\">LONGER BATTERY LIFE — iPhone 16 works together with the A18 chip to deliver a big boost in battery life with up to 22 hours video playback. Charge via USB-C or snap on a MagSafe charger for faster wireless charging.</li></ul></div></div>', NULL, NULL, NULL, 15000.00, 20000.00, 1, 14, 7, 'Yes', 'sku-05', 'barcode-05', 'Yes', -9, 1, '2025-08-18 06:03:03', '2026-02-17 11:37:02'),
(6, 'Party Wear Girls casual shoes', 'party-wear-girls-casual-shoes', '<p><span style=\"color: rgb(27, 29, 29); font-family: Roboto, Arial, sans-serif; font-size: 13px; text-align: justify;\">We are Manufacturer of all types of Men\'s Shoes and Footwear Range like Casual Shoes, Formal Shoes, Loafer Shoes, Boots, Party Shoes, Dress Shoes, Slippers, Sandals, Ethnic Shoes, Designer Shoes, Safety Shoes, Leather Shoes, Moccasins Shoes, Sport Shoes, Black Boots, Leather Boots, Leather Casual Shoes, Man sandals, Women Sandals, Women Casual Shoes, Man Causal Shoes, Floaters, Slipper &amp; Floaters, Running Shoes, Canvas Shoes, Sneakers Shoes, Flip- Flop, Height Increasing Shoes, Women High Heels, Ankle Boots, Women Ankle Boots, Men Ankle Boots, Woman Boots, Woman Formal Shoes, Ladies Shoes, Girls Shoes, Uniform Shoes, School Shoes, Women\'s Flats, Girl\'s Flats, Ballet Shoes, Formal Shoes ,Handmade Formal Shoes ,Ladies Formal Shoes ,Men\'s Formal Shoes ,Leather Formal Shoes ,Gents Formal Shoes ,Men\'s Designer Formal Shoes ,Corporate Formal Shoes ,Black Formal Shoes ,Formal Slip on Shoes ,Traditional Formal Shoes ,Party Formal Shoes ,Casual Shoes ,Gents Casual Shoes ,Ladies Casual Shoes ,Men Casual Shoes ,Trendy Men Casual Shoes ,Leather Boots ,Non Leather Boots ,Leather Shoes for Men ,Moccasins Shoes ,Women Sandals ,Men Slippers ,Loafers ,Gents Loafer, Stylish Loafer ,Trendy Loafers.</span></p>', NULL, NULL, NULL, 12000.00, 15000.00, 2, 17, 1, 'No', 'sku-06', 'barcode-06', 'Yes', 2, 0, '2025-08-18 06:06:47', '2025-08-18 06:06:47'),
