(8, 'Puma Shooes', 'puma-shooes', '<div class=\"tabName\" aria-hidden=\"true\" style=\"outline: transparent; margin: 0px 0px 5px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-weight: 700; font-stretch: inherit; font-size: 14px; line-height: inherit; font-family: SourceSansPro; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; border-radius: 0px; color: rgb(51, 51, 51);\">Additional Information 1</div><div class=\"detail-list  \" aria-hidden=\"true\" style=\"outline: transparent; margin: 0px; padding: 0px 0px 10px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; font-size: 14px; line-height: inherit; font-family: SourceSansPro; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; border-radius: 0px; position: relative; color: rgb(51, 51, 51); -webkit-line-clamp: 3;\">Product story: With its huge impact on footwear culture, PUMA\'s most iconic trainer first hit the scene in 1968 and has been worn by icons of every generation since. The Suede Classic XXI Sneakers features a full suede upper alongside some modern touches for an improved overall quality and feel to an all-time great.</div>', NULL, NULL, NULL, 20000.00, 25000.00, 2, 16, 1, 'No', 'sku-08', 'barcode-08', 'Yes', 15, 1, '2025-08-18 06:12:05', '2025-08-18 06:12:05'),
(9, 'Girls Jeans Skinny Denim', 'girls-jeans-skinny-denim', '<h3 class=\"product-facts-title\" style=\"padding: 4px 0px 14px; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; text-rendering: optimizelegibility; font-weight: 700; font-size: 18px; line-height: 24px; color: rgb(15, 17, 17); font-family: &quot;Amazon Ember&quot; !important;\">About this item</h3><ul class=\"a-unordered-list a-vertical a-spacing-small\" style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 18px; color: rgb(15, 17, 17); padding: 0px; font-family: Arial, sans-serif; font-size: 14px;\"><li style=\"list-style: disc; overflow-wrap: break-word; margin: 0px;\"><span class=\"a-list-item a-size-base a-color-base\" style=\"line-height: 20px !important;\">Comfortable and Fashionable: These girls\' jeans are made of washed denim fabric, which is hard wearing and durable to withstand daily wear and tear. 100% cotton fabric ensures the softness and breathabiliy, so you can wear them all year round without worrying about the shape or color of the trousers changing.</span></li><li style=\"list-style: disc; overflow-wrap: break-word; margin: 0px;\"><span class=\"a-list-item a-size-base a-color-base\" style=\"line-height: 20px !important;\">Ripped Skinny Jeans: Washed denim fabric creates these girl\'s jeggings with an elasticated waistband. High waisted slim fit with a beautiful silhouette. Skinny ankle length shows off curvy legs even more. Ripped and distressed detailing adds an edgy and stylish touch!</span></li><li style=\"list-style: disc; overflow-wrap: break-word; margin: 0px;\"><span class=\"a-list-item a-size-base a-color-base\" style=\"line-height: 20px !important;\">5 Pocket Jean: Multiple pockets at the front and back, 1 coin pocket and 2 pockets at the front, 2 pockets at the back, can provide practical storage space for small objects.</span></li><li style=\"list-style: disc; overflow-wrap: break-word; margin: 0px;\"><span class=\"a-list-item a-size-base a-color-base\" style=\"line-height: 20px !important;\">Various Match: Girls ripped wide leg jeans are very versatile, allowing you to create a variety of stylish outfits. Pair them with t shirts, tank, shirts, hoodies, jumpers, sweatshirts, jackets coats or sports shoes for a casual cool girl look!</span></li></ul>', NULL, NULL, NULL, 2000.00, 3000.00, 6, 20, 1, 'No', 'sku-09', 'barcode-09', 'Yes', 9, 1, '2025-08-18 06:16:07', '2026-02-23 12:42:26'),
