(42, 'M1 MacBook Air', 'm1-macbook-air', '<h2 style=\"font-family: Roboto, sans-serif; color: rgb(17, 17, 17); margin: 30px 0px 20px; font-size: 27px; line-height: 38px;\"><strong style=\"font-weight: bold;\">Macbook Air M1 Specifications:</strong></h2><h1 class=\"entry-title\" style=\"font-family: Roboto, sans-serif; color: rgb(51, 51, 51); margin-right: 0px; margin-bottom: 7px; margin-left: 0px; font-size: 41px; line-height: 50px; overflow-wrap: break-word; padding: 7px 0px;\"><ul style=\"padding: 0px; margin-bottom: 26px; color: rgb(34, 34, 34); font-family: Roboto; font-size: 16px;\"><li style=\"line-height: inherit; margin-left: 21px; margin-bottom: 10px;\"><strong style=\"font-weight: bold;\">Dimension:&nbsp;</strong>0.16-0.63H x 11.97W x 8.36D-inches, 1.29kg</li><li style=\"line-height: inherit; margin-left: 21px; margin-bottom: 10px;\"><strong style=\"font-weight: bold;\">Display</strong>: 13.3-inch Retina IPS display; True Tone technology; P3 Wide Color; 400 nits</li><li style=\"line-height: inherit; margin-left: 21px; margin-bottom: 10px;\"><strong style=\"font-weight: bold;\">Resolution</strong>: 2560 x 1600 pixels; 16:10 aspect ratio</li><li style=\"line-height: inherit; margin-left: 21px; margin-bottom: 10px;\"><strong style=\"font-weight: bold;\">CPU</strong>: Apple M1 chip (5nm)</li><li style=\"line-height: inherit; margin-left: 21px; margin-bottom: 10px;\"><strong style=\"font-weight: bold;\">RAM</strong>: 8/16GB</li><li style=\"line-height: inherit; margin-left: 21px; margin-bottom: 10px;\"><strong style=\"font-weight: bold;\">Storage</strong>: up to 2TB SSD</li><li style=\"line-height: inherit; margin-left: 21px; margin-bottom: 10px;\"><strong style=\"font-weight: bold;\">OS</strong>: macOS Big Sur</li><li style=\"line-height: inherit; margin-left: 21px; margin-bottom: 10px;\"><strong style=\"font-weight: bold;\">Keyboard</strong>: Backlit Magic Keyboard</li><li style=\"line-height: inherit; margin-left: 21px; margin-bottom: 10px;\"><strong style=\"font-weight: bold;\">Camera</strong>: 720p FaceTime HD camera</li><li style=\"line-height: inherit; margin-left: 21px; margin-bottom: 10px;\"><strong style=\"font-weight: bold;\">Ports</strong>: 2x USB-C Thunderbolt 3 ports, 3.5mm headphone jack</li><li style=\"line-height: inherit; margin-left: 21px; margin-bottom: 10px;\"><strong style=\"font-weight: bold;\">Connectivity</strong>: 802.11 a/b/g/n/ac/ax WiFi, Bluetooth 5.0</li><li style=\"line-height: inherit; margin-left: 21px; margin-bottom: 10px;\"><strong style=\"font-weight: bold;\">Battery</strong>: 49.9Whr LiPo Battey; 30W USB-C power adapter</li><li style=\"line-height: inherit; margin-left: 21px; margin-bottom: 10px;\"><strong style=\"font-weight: bold;\">Color options</strong>: Space Grey, Silver, and Gold</li></ul></h1>', NULL, NULL, NULL, 400.00, 400.00, 1, 27, 18, '', 'sku-42', 'barcode-42', 'Yes', 5, 1, '2025-09-04 03:43:00', '2025-09-06 06:22:02'),
(43, 'Apple 2024 MacBook Pro Laptop', 'apple-2024-macbook-pro-laptop', '<p>Apple 2024 MacBook Pro Laptop<br></p><h1 id=\"title\" class=\"a-size-large a-spacing-none\" style=\"padding: 0px; margin-right: 0px; margin-left: 0px; text-rendering: optimizelegibility; color: rgb(15, 17, 17); font-family: &quot;Amazon Ember&quot;, Arial, sans-serif; margin-bottom: 0px !important; font-size: 24px !important; line-height: 32px !important;\"><span id=\"productTitle\" class=\"a-size-large product-title-word-break\" style=\"text-rendering: optimizelegibility; word-break: break-word; line-height: 32px !important;\">Apple 2024 MacBook Pro Laptop with M4 chip with 10‑core CPU and 10‑core GPU: Built for Apple Intelligence, 35.97 cm (14.2″) Liquid Retina XDR Display, 16GB Unified Memory, 512GB SSD Storage; Silver</span></h1><h1 id=\"title\" class=\"a-size-large a-spacing-none\" style=\"padding: 0px; margin-right: 0px; margin-left: 0px; text-rendering: optimizelegibility; color: rgb(15, 17, 17); font-family: &quot;Amazon Ember&quot;, Arial, sans-serif; margin-bottom: 0px !important; font-size: 24px !important; line-height: 32px !important;\"><span id=\"productTitle\" class=\"a-size-large product-title-word-break\" style=\"text-rendering: optimizelegibility; word-break: break-word; line-height: 32px !important;\"><br></span></h1><h1 class=\"a-size-base-plus a-text-bold\" style=\"padding: 0px 0px 4px; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; text-rendering: optimizelegibility; color: rgb(15, 17, 17); font-weight: 700 !important; font-size: 1.25rem !important; line-height: 24px !important; font-family: &quot;Amazon Ember&quot; !important;\">About this item</h1><h1 id=\"title\" class=\"a-size-large a-spacing-none\" style=\"padding: 0px; margin-right: 0px; margin-left: 0px; text-rendering: optimizelegibility; color: rgb(15, 17, 17); font-family: &quot;Amazon Ember&quot;, Arial, sans-serif; margin-bottom: 0px !important; font-size: 24px !important; line-height: 32px !importa