></h1>', NULL, NULL, NULL, 2500.00, 3000.00, 1, 27, 18, 'Yes', 'sku-43', 'barcode-43', 'Yes', 5, 1, '2025-09-04 03:45:27', '2025-09-06 04:09:58'),
