(60, 'Whirlpool Refrigirator Cold L-46 L', 'whirlpool-refrigirator-cold-l-46-l', '<p><div class=\"spacer baseComponent aem-GridColumn--default--none aem-GridColumn--phone--none aem-GridColumn--phone--11 aem-GridColumn aem-GridColumn--default--8 aem-GridColumn--offset--default--2 aem-GridColumn--offset--phone--0\" style=\"box-sizing: border-box; clear: none; display: block; float: left; width: 780px; margin-left: 195px; color: rgb(0, 0, 0); font-family: &quot;Helvetica Neue LT W01_55 Roman&quot;, Helvetica, Arial; font-size: 16px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(255, 255, 255); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\"></div></p><div class=\"richText text aem-GridColumn--default--none aem-GridColumn--phone--none aem-GridColumn--phone--12 aem-GridColumn aem-GridColumn--default--8 aem-GridColumn--offset--default--2 aem-GridColumn--offset--phone--0\" style=\"box-sizing: border-box; clear: none; display: block; float: left; width: 780px; margin-left: 195px; color: rgb(0, 0, 0); font-family: &quot;Helvetica Neue LT W01_55 Roman&quot;, Helvetica, Arial; font-size: 16px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(255, 255, 255); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\"><div id=\"richText-ba18c988ac\" class=\"platform-components-rich-text  platform-components-rich-text--theme-01  lg:pt0 lg:pr0 lg:pb0 lg:pl0 pr2 pl0\" style=\"box-sizing: inherit; padding: 0px; font-family: &quot;Helvetica Neue LT W01_55 Roman&quot;, Helvetica, Arial; font-size: 16px; position: relative; color: rgb(34, 34, 34);\"><p style=\"box-sizing: inherit; margin: 0px; font-family: &quot;Helvetica Neue LT W01_55 Roman&quot;, Helvetica, Arial; color: rgb(34, 34, 34); font-size: 1rem; line-height: 24px; font-weight: 400; text-transform: none; letter-spacing: 0.016rem;\">Whether it’s mealtime or snacktime,&nbsp;you depend on your refrigerator to keep foods fresh for the entire family. This visual guide will help you identify the parts of a refrigerator and<span>&nbsp;</span><a title=\"Learn how refrigerators work\" href=\"https://www.whirlpool.com/blog/kitchen/how-do-refrigerators-work.html\" style=\"box-sizing: inherit; background-color: transparent; color: rgb(0, 0, 0); text-decoration: underline; font-weight: bold; font-size: 16.8px;\"><b style=\"box-sizing: inherit; font-weight: 700; font-size: 16.8px; font-family: &quot;Helvetica Neue LT W01_71488914&quot;, &quot;Helvetica Bold&quot;, &quot;Arial Bold&quot;, sans-serif; color: rgb(34, 34, 34);\">how they work</b></a><span>&nbsp;</span>to keep the internal compartments of the fridge cool. You’ll also find answers to the most common questions about refrigerator components and accessories. Select a link below to jump to each section and learn more about how the parts of a refrigerator work to fuel your busy kitchen.</p></div></div>', NULL, NULL, NULL, 12000.00, NULL, 1, 26, 5, 'No', 'sku-60', 'barcode-60', 'Yes', 10, 1, '2025-09-05 05:39:41', '2025-09-05 05:39:41'),
(61, 'Samsung Refrez Cold 33 L, U-123', 'samsung-refrez-cold-33-l-u-123', '<p><span style=\"color: rgb(34, 34, 34); font-family: &quot;Helvetica Neue LT W01_55 Roman&quot;, Helvetica, Arial; letter-spacing: 0.256px;\">Think of your compressor as the heart of your fridge. By pumping vapor refrigerant through the fridge, the compressor increases the temperature and pressure of the cooling agent. The compressor is often found at the back or bottom of the fridge.</span></p>', '<span style=\"color: rgb(34, 34, 34); font-family: &quot;Helvetica Neue LT W01_55 Roman&quot;, Helvetica, Arial; letter-spacing: 0.256px;\">Think of your compressor as the heart of your fridge. </span>', NULL, '', 4500.00, 5500.00, 1, 26, 5, '', 'sku-61', 'barcode-61', 'Yes', 10, 1, '2025-09-05 05:43:08', '2026-02-23 05:07:11'),
