(66, 'LG 201 Litres 5 Star Direct Cool Single Door Refrigerator', 'lg-201-litres-5-star-direct-cool-single-door-refrigerator', '<p>LG 201 Litres 5 Star Direct Cool Single Door Refrigerator with Antibacterial Gasket (GL-D211HSEZ, Scarlet Euphoria)</p><p><span style=\"color: rgb(255, 255, 255); font-family: Switzer; font-size: 16.8px; letter-spacing: 1px; background-color: rgb(25, 25, 25);\">Built with an amazing 201L storage capacity the LG GL-D211HSEZ 201L Manual Defrost Single-Door Refrigerator allows for the effortless storage of fresh produce leftover casseroles weekly groceries frozen goods and more. Furthermore its area efficiently accommodates oversized cartons of milk and massive beverage bottles. Hence households with 3 family members can find a practical and efficient storage solution in this refrigerator.</span><br style=\"font-family: Switzer; color: rgb(255, 255, 255); font-size: 16.8px; letter-spacing: 1px; background-color: rgb(25, 25, 25);\"><br style=\"font-family: Switzer; color: rgb(255, 255, 255); font-size: 16.8px; letter-spacing: 1px; background-color: rgb(25, 25, 25);\"><br style=\"font-family: Switzer; color: rgb(255, 255, 255); font-size: 16.8px; letter-spacing: 1px; background-color: rgb(25, 25, 25);\"><span style=\"margin: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; font-size: 16.8px; line-height: inherit; font-family: Switzer; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: initial; color: rgb(255, 255, 255); letter-spacing: 1px; background-color: rgb(25, 25, 25);\">Direct Cool Technology</span><br style=\"font-family: Switzer; color: rgb(255, 255, 255); font-size: 16.8px; letter-spacing: 1px; background-color: rgb(25, 25, 25);\"><br style=\"font-family: Switzer; color: rgb(255, 255, 255); font-size: 16.8px; letter-spacing: 1px; background-color: rgb(25, 25, 25);\"><span style=\"color: rgb(255, 255, 255); font-family: Switzer; font-size: 16.8px; letter-spacing: 1px; background-color: rgb(25, 25, 25);\">Featuring Direct Cool technology this refrigerator eliminates hotspots and ensures uniform cooling preserving the quality of your stored items. So you can plan elaborate dinner parties without the stress of last-minute grocery runs as this refrigerator ensures prolonged freshness.</span></p>', NULL, NULL, NULL, 1200.00, 2000.00, 1, 26, 5, '', 'sku-66', 'barcode-66', 'Yes', 5, 1, '2025-09-06 03:35:16', '2025-09-06 03:35:53'),
(67, 'LG 398L Double Door Refrigerator, Convertible', 'lg-398l-double-door-refrigerator-convertible', '<p>LG 398L Double Door Refrigerator, Convertible, Wi-Fi, Door Cooling™, Shiny Steel Finish, 3 Star</p><p><span style=\"color: rgb(74, 73, 70); font-family: &quot;LGEI Text&quot;, &quot;Segoe UI&quot;, &quot;Microsoft Sans Serif&quot;, sans-serif; background-color: rgb(240, 236, 228);\">*LG SmartThinQ is now renamed to AI ThinQ.</span><br style=\"font-family: &quot;LGEI Text&quot;, &quot;Segoe UI&quot;, &quot;Microsoft Sans Serif&quot;, sans-serif; scrollbar-width: thin; color: rgb(74, 73, 70); background-color: rgb(240, 236, 228);\"><span style=\"color: rgb(74, 73, 70); font-family: &quot;LGEI Text&quot;, &quot;Segoe UI&quot;, &quot;Microsoft Sans Serif&quot;, sans-serif; background-color: rgb(240, 236, 228);\">*Smart feature products may vary by country and model. Check your local retailer or LG for service availability.</span><br style=\"font-family: &quot;LGEI Text&quot;, &quot;Segoe UI&quot;, &quot;Microsoft Sans Serif&quot;, sans-serif; scrollbar-width: thin; color: rgb(74, 73, 70); background-color: rgb(240, 236, 228);\"><span style=\"color: rgb(74, 73, 70); font-family: &quot;LGEI Text&quot;, &quot;Segoe UI&quot;, &quot;Microsoft Sans Serif&quot;, sans-serif; background-color: rgb(240, 236, 228);\">*UIs (User Interfaces) of Apps in the image are for explanation purpose only and may differ from actual ones.</span><br style=\"font-family: &quot;LGEI Text&quot;, &quot;Segoe UI&quot;, &quot;Microsoft Sans Serif&quot;, sans-serif; scrollbar-width: thin; color: rgb(74, 73, 70); background-color: rgb(240, 236, 228);\"><span style=\"color: rgb(74, 73, 70); font-family: &quot;LGEI Text&quot;, &quot;Segoe UI&quot;, &quot;Microsoft Sans Serif&quot;, sans-serif; background-color: rgb(240, 236, 228);\">*Products in the image are for explanation purpose only and may differ from actual ones.</span></p>', NULL, NULL, NULL, 2000.00, 2200.00, 1, 26, 5, '', 'sku-67', 'barcode-67', 'Yes', 5, 1, '2025-09-06 03:37:55', '2025-09-06 03:43:06'),
(68, '615 L Convertible 5in1 Side by Side Refrigerator', '615-l-convertible-5in1-side-by-side-refrigerator', '<p>615 L Convertible 5in1 Side by Side Refrigerator RS7HCG8543B1</p><h2 class=\"feature-benefit__title contrast-target\" data-font-size-mo=\"30\" data-font-size-pc=\"48\" style=\"margin-right: auto; margin-bottom: 0px; margin-left: auto; padding: 0px; vertical-align: top; font-size: 48px; font-family: SamsungSharpSans, arial, sans-serif; font-weight: bold; overflow-wrap: break-word;\">Up to 10% Energy Saving</h2><div class=\"feature-benefit__desc-wrap\" style=\"margin: 0px auto; padding: 0px; vertical-align: top;\"><h3 class=\"feature-benefit__sub-title contrast-target\" data-font-size-mo=\"16\" data-font-size-pc=\"28\" style=\"margin: 48px 0px 0px; padding: 0px; vertical-align: top; font-size: 28px; font-weight: bold; overflow-wrap: break-word; line-height: 1.33; color: rgb(0, 0, 0); font-family: SamsungOne, arial, sans-serif;\">SmartThings AI Energy Mode</h3><p class=\"feature-benefit__desc contrast-target\" data-font-size-mo=\"12\" data-font-size-pc=\"18\" style=\"margin: 32px 0px 0px; padding: 0px; vertical-align: top; font-size: 18px; line-height: 1.33; overflow-wrap: break-word; color: rgb(0, 0, 0); font-family: SamsungOne, arial, sans-serif;\">Monitor and proactively save energy. AI Energy Mode* analyses your refrigerator usage patterns and estimates power consumption, based on AI technology. If the estimated electric bill exceeds your preset target, it recommends you to activate the saving mode to reduce energy use by up to 10%***.</p><div><br></div></div>', NULL, NULL, NULL, 10000.00, 15000.00, 1, 26, 5, '', 'sku-68', 'barcode-68', 'Yes', 8, 1, '2025-09-06 03:42:29', '2026-02-26 12:37:26'),
(69, 'LG 446 L 1 Double Door Refrigerator', 'lg-446-l-1-double-door-refrigerator', '<p>LG 446 L 1 Star Double Door Refrigerator with Smart Inverter Compressor (GL-T502CESR, Ebony Sheen)</p>', 'LG 446 L 1 Double Door Refrigerator', NULL, '', 5000.00, 6000.00, 1, 26, 5, 'Yes', 'sku-69', 'barcode-69', 'Yes', 3, 1, '2025-09-06 03:47:37', '2025-09-12 00:32:20'),
