(71, 'MacBook Air 13-U', 'macbook-air-13-u', '<div class=\"dcomppro_head mb-10 font20 fw600 color414\" style=\"outline: none medium; margin: 0px 0px 10px; padding: 0px; font-family: Poppins, sans-serif; font-weight: 600; font-size: 20px; color: rgb(17, 17, 17); display: inline-flex; width: 654px; -webkit-box-align: center; align-items: center; -webkit-box-pack: justify; justify-content: space-between; letter-spacing: -0.2px;\">Description</div><div class=\"dcomppro_head mb-10 font20 fw600 color414\" style=\"outline: none medium; margin: 0px 0px 10px; padding: 0px; display: inline-flex; width: 654px; -webkit-box-align: center; align-items: center; -webkit-box-pack: justify; justify-content: space-between;\"><a class=\"dcomppro_anchor font14 fw400 color007\" style=\"outline: none; margin: 0px; padding: 0px; border: 0px; cursor: pointer;\"><font color=\"#0076d7\" face=\"Poppins, sans-serif\"><span style=\"font-size: 14px; letter-spacing: -0.2px;\">MacBook Air is the world’s most popular laptop for a reason. Actually, for a lot of reasons. It delivers up to 18 hours of battery life.2 The M4 chip unlocks a whole new level of performance for work and play. Apple Intelligence is built in to help you get things done effortlessly.1 And it now comes in a stunning Sky Blue colour. With the perfectly portable MacBook Air, you’ll be ready to take on just about anything, anywhere.</span></font></a></div><div class=\"dcomppro_desc font16 fw400 color414 specsTbl pagebox discr \" style=\"outline: none medium; margin: 0px; padding: 0px; font-family: Poppins, sans-serif; display: -webkit-box; width: 654px; table-layout: fixed; vertical-align: top; font-size: medium; color: rgb(17, 17, 17); overflow: hidden; -webkit-line-clamp: 6; z-index: 9999; -webkit-box-orient: vertical; line-height: 27px; max-height: 185px; letter-spacing: -0.2px;\"><div style=\"outline: none medium; margin: 0px; padding: 0px; font-family: Poppins, &quot;Helvetica Neue&quot;, sans-serif; font-size: 16px;\">Introducing the Second Hand Apple Laptop, a high-performing device that combines sleek design with powerful functionality. This laptop is meticulously refurbished to provide you with an exceptional computing experience at an affordable price. Equipped with the latest Apple technologies and a reliable processor, it delivers incredible speed and responsiveness. With its crisp Retina display, you can enjoy vibrant visuals and sharp details. This lightweight laptop is</div></div>', NULL, NULL, NULL, 15000.00, NULL, 1, 27, 18, '', 'sku-71', 'barcode-3271', 'Yes', 5, 1, '2025-09-06 03:57:26', '2025-09-06 06:15:47'),
(72, 'MacBook Pro with M1 Pro and M1 Max', 'macbook-pro-with-m1-pro-and-m1-max', '<div class=\"pagebody-copy\" style=\"margin-bottom: 1.4211em; color: rgb(29, 29, 31); font-family: &quot;SF Pro Display&quot;, &quot;SF Pro Icons&quot;, &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 19px; letter-spacing: 0.228px;\">Featuring the same powerful 10-core CPU in M1 Pro and M1 Max, the 16-inch MacBook Pro delivers:<ul style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; margin-inline-start: 1.17647em;\"><li style=\"margin: 0px; padding: 0px;\">Up to 3x faster computational fluid dynamics performance in NASA TetrUSS.</li><li style=\"margin: 0px; padding: 0px;\">Up to 2.1x faster project builds in Xcode.</li><li style=\"margin: 0px; padding: 0px;\">Up to 2.1x faster publish performance in Vectorworks.</li></ul></div><div class=\"pagebody-copy\" style=\"margin-bottom: 1.4211em; color: rgb(29, 29, 31); font-family: &quot;SF Pro Display&quot;, &quot;SF Pro Icons&quot;, &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 19px; letter-spacing: 0.228px;\">With the 16-core GPU in M1 Pro and 32-core GPU in M1 Max, the 16-inch MacBook Pro offers faster graphics performance with:<ul style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; margin-inline-start: 1.17647em;\"><li style=\"margin: 0px; padding: 0px;\">Up to 2.9x faster combined vector and raster GPU performance in Affinity Photo with M1 Pro, and up to 4.5x faster with M1 Max.</li><li style=\"margin: 0px; padding: 0px;\">Up to 2.5x faster render in Maxon Cinema 4D with Redshift with M1 Pro, and up to 4x faster with M1 Max.</li><li style=\"margin: 0px; padding: 0px;\">Up to 1.7x faster 8K render in Final Cut Pro with M1 Pro, and up to 2.9x faster with M1 Max.</li></ul></div><div class=\"pagebody-copy\" style=\"margin-bottom: 0px; color: rgb(29, 29, 31); font-family: &quot;SF Pro Display&quot;, &quot;SF Pro Icons&quot;, &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 19px; letter-spacing: 0.228px;\">With the 16-core Neural Engine on both M1 Pro and M1 Max, ML tasks are faster than ever on the 16-inch MacBook Pro, including:<ul style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; margin-inline-start: 1.17647em;\"><li style=\"margin: 0px; padding: 0px;\">Up to 4.4x faster scene edit detection in 1080p ProRes 422 video in Adobe Premiere Pro.</li><li style=\"margin: 0px; padding: 0px;\">Up to 3.6x faster object tracking performance in Final Cut Pro with M1 Pro, and up to 4.9x faster with M1 Max.</li><li style=\"margin: 0px; padding: 0px;\">Up to 1.5x faster performance with M1 Pro and up to 2x faster with M1 Max when selecting subjects in images in Adobe Photoshop.</li></ul></div>', NULL, NULL, NULL, 12000.00, 15000.00, 1, 27, 18, '', 'sku-72', 'barcode-72', 'No', NULL, 1, '2025-09-06 04:00:55', '2025-09-06 06:15:39'),
(73, 'M1 chips inside some Apple MacBooks', 'm1-chips-inside-some-apple-macbooks', '<p>The M1 chips inside some Apple MacBooks are well suited to big computation tasks</p>', 'The M1 chips inside some Apple MacBooks are well suited to big computation tasks', NULL, '', 6000.00, 6500.00, 1, 27, 18, '', 'sku-73', 'barcode-73', 'Yes', 12, 1, '2025-09-06 04:04:36', '2025-09-18 03:40:11'),
