(77, 'Dell Latitude 5420 i3-1125G4 16GB 512GB SSD M.2', 'dell-latitude-5420-i3-1125g4-16gb-512gb-ssd-m2', '<p>Dell Latitude 5420 i3-1125G4 16GB 512GB SSD M.2 1920x1080 Class A Windows 11 Professional</p><div class=\"feature\" style=\"margin: 0px 0px 5px; padding: 0px; color: rgb(21, 21, 21); font-family: poppinssemibold, sans-serif;\">Vibrant Display</div><div class=\"description\" style=\"margin: 0px; padding: 0px; font-size: 14px; color: rgb(102, 102, 102); font-family: poppinsregular, sans-serif;\">The 15.6-inch Full HD display offers stunning visuals, perfect for multimedia tasks, ensuring clarity and detail for both entertainment and productivity.</div><div class=\"description\" style=\"margin: 0px; padding: 0px; font-size: 14px; color: rgb(102, 102, 102); font-family: poppinsregular, sans-serif;\"><div class=\"heading-sec\" style=\"margin: 0px 0px 24px; padding: 0px 0px 15px; border-bottom: 3px solid rgb(247, 247, 247); position: relative; display: flex; justify-content: space-between; align-items: center; color: rgb(33, 37, 41); font-family: poppinssemibold, sans-serif;\"><h2 class=\"heading\" style=\"padding: 0px; line-height: 1; font-family: poppinssemibold, sans-serif; color: rgb(21, 21, 21); margin-right: 0px !important; margin-bottom: 0px !important; margin-left: 0px !important; font-size: 20px !important;\">Product Details</h2></div><div class=\"Product Details\" id=\"rewrite_description\" style=\"margin: 0px; padding: 0px; color: rgb(33, 37, 41); font-family: poppinssemibold, sans-serif;\"><ul class=\"product-points\" itemprop=\"description\" style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; list-style: none;\"><li style=\"margin: 0px 0px 20px; padding: 0px 0px 0px 28px; list-style: none; font-family: poppinsregular, sans-serif; color: rgb(21, 21, 21); display: flex; align-items: center; position: relative;\">Refurbished Dell Inspiron 15 5570 15.6 Laptop Computer - Silver</li><li style=\"margin: 0px 0px 20px; padding: 0px 0px 0px 28px; list-style: none; font-family: poppinsregular, sans-serif; color: rgb(21, 21, 21); display: flex; align-items: center; position: relative;\">Tested and certified to look and work like new</li><li style=\"margin: 0px 0px 20px; padding: 0px 0px 0px 28px; list-style: none; font-family: poppinsregular, sans-serif; color: rgb(21, 21, 21); display: flex; align-items: center; position: relative;\">8th Gen Intel Core processor for powerful performance</li><li style=\"margin: 0px 0px 20px; padding: 0px 0px 0px 28px; list-style: none; font-family: poppinsregular, sans-serif; color: rgb(21, 21, 21); display: flex; align-items: center; position: relative;\">8GB memory and 1TB hard drive for heavy-duty multitasking</li><li style=\"margin: 0px 0px 20px; padding: 0px 0px 0px 28px; list-style: none; font-family: poppinsregular, sans-serif; color: rgb(21, 21, 21); display: flex; align-items: center; position: relative;\">15.6-inch Full HD touchscreen for a sharp view</li><li style=\"margin: 0px; padding: 0px 0px 0px 28px; list-style: none; font-family: poppinsregular, sans-serif; color: rgb(21, 21, 21); display: flex; align-items: center; position: relative;\">Backlit keyboard and precision touchpad for convenient use</li></ul></div></div>', NULL, NULL, NULL, 600.00, 750.00, 1, 27, 4, '', 'sku-77', 'barcode-77', 'No', NULL, 1, '2025-09-07 23:14:17', '2025-09-07 23:18:40'),
(78, 'ASUS Zenbook 14 (UM3406)', 'asus-zenbook-14-um3406', '<p>ASUS Zenbook 14 (UM3406)</p><p><span style=\"color: rgb(77, 77, 77); font-family: Roboto, sans-serif; font-size: 1rem;\">Windows 11 Home - ASUS recommends Windows 11 Pro for business</span></p><p><span style=\"color: rgb(77, 77, 77); font-family: Roboto, sans-serif; font-size: 1rem;\">Thin and light: 14.9 mm, 1.2 k</span></p><p><span style=\"color: rgb(77, 77, 77); font-family: Roboto, sans-serif; font-size: 1rem;\">AMD Ryzen™ AI 300 Series Processor</span></p><p><span style=\"color: rgb(77, 77, 77); font-family: Roboto, sans-serif; font-size: 1rem;\">Long-lasting 75 Wh battery&nbsp;</span></p><p><span style=\"color: rgb(77, 77, 77); font-family: Roboto, sans-serif; font-size: 1rem;\">35.56cm (14), 3K 120Hz OLED HDR display</span></p><p><span style=\"color: rgb(77, 77, 77); font-family: Roboto, sans-serif; font-size: 1rem;\">16 GB memory</span></p><p><span style=\"color: rgb(77, 77, 77); font-family: Roboto, sans-serif; font-size: 1rem;\">512 GB SSD storage</span></p><p><span style=\"color: rgb(77, 77, 77); font-family: Roboto, sans-serif; font-size: 1rem;\">Full IO ports with USB 4 Type-C</span><span style=\"color: rgb(77, 77, 77); font-family: Roboto, sans-serif; font-size: 12px; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em;\">®</span></p>', 'ASUS Zenbook 14 (UM3406),&nbsp;<span style=\"color: rgb(77, 77, 77); font-family: Roboto, sans-serif; font-size: 1rem;\">Windows 11 Home - ASUS recommends Windows 11 Pro for business</span><div><span style=\"color: rgb(77, 77, 77); font-family: Roboto, sans-serif; font-size: 1rem;\"><br></span></div>', NULL, '', 6.00, 71000.00, 1, 27, 1, '', 'sku-78', 'barcode-78', 'Yes', 5, 1, '2025-09-07 23:18:22', '2025-10-08 23:26:45'),
(79, 'ASUS Zenbook 14 OLED', 'asus-zenbook-14-oled', '<p>ASUS Zenbook 14 OLED</p><p style=\"margin-right: 0px; margin-bottom: 20px; margin-left: 0px; padding: 0px; font-size: 18px; line-height: 28px; color: rgb(0, 0, 0); font-family: Rubik, helvatica, Arial, sans-serif;\">The ROG Zephyrus G16 is for both gamers and content creators. It comes equipped with the AMD Ryzen AI 9 HX 370 Processor and up to an NVIDIA GeForce RTX 4070 GPU. The laptop features a QHD+ 240Hz ROG Nebula Display with a 0.2ms response time and 500 nits brightness. Weighing just 1.85 kg and measuring as slim as 14.9mm, this aluminum CNC unibody laptop is designed for portability and performance. It offers a 90Wh battery with fast charging, Wi-Fi 7, and a comprehensive set of I/O ports, including a 40Gbps USB 4 Type-C port and a full-sized UHS-II SD card reader.</p><div><br></div>', NULL, NULL, NULL, 500.00, 600.00, 1, 27, 4, 'No', 'sku-79', 'barcode-79', 'Yes', 5, 1, '2025-09-07 23:22:01', '2025-09-07 23:22:01'),
(80, 'iPad Pro', 'ipad-pro', '<p>iPad Pro</p><ul data-core-accordion=\"\" id=\"question\" class=\"rc-accordion rf-faqsection-wrapper rc-accordion-compact\" role=\"list\" style=\"padding: 0px; margin-inline-start: 1.17647em; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; list-style: none; color: rgb(29, 29, 31); font-family: &quot;SF Pro Text&quot;, &quot;SF Pro Icons&quot;, &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 17px; letter-spacing: -0.374px;\"><li data-core-accordion-item=\"\" class=\"rc-accordion-item\" role=\"listitem\" data-core-accordion-item-expanded=\"\" style=\"margin: 0px; padding: 0px; font-size: 1em; border-top: 1px solid rgb(210, 210, 215);\"><h3 style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(29, 29, 31); font-weight: 600;\"><button type=\"button\" data-core-accordion-button=\"\" aria-expanded=\"true\" aria-controls=\"content-question-0\" id=\"title-question-0\" class=\"rc-accordion-button\" data-core-accordion-button-expanded=\"\" style=\"padding: 17px 0px; background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-width: 0px; border-style: initial; border-color: initial; box-sizing: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: inherit; -webkit-font-smoothing: antialiased; font-synthesis: none; align-items: center; display: flex; width: 980px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0);\"><span class=\"rc-accordion-title large-10 typography-callout\" style=\"flex-basis: 83.3333%; max-width: 83.3333%; font-size: 17px; letter-spacing: -0.022em; line-height: 1.23536; text-align: start;\">What is the difference in display glass options?</span><span class=\"icon rc-accordion-collapse-icon\" style=\"margin-inline-start: auto;\"></span><span class=\"rc-accordion-chevrondown rc-accordion-collapse-icon\" style=\"align-items: flex-start; align-self: baseline; display: flex; justify-content: center; margin: 0px; transition: color 0.1s linear; width: 32px; stroke-width: 2.25; color: rgb(134, 134, 139); position: relative; margin-inline-start: auto;\"><svg class=\"accordion-icon-svg\" viewBox=\"0 0 17 8.85\" height=\"35px\" width=\"35px\"><polyline data-accordion-icon-shape=\"\" stroke=\"currentColor\" stroke-linecap=\"round\" stroke-linejoin=\"round\" fill=\"none\" fill-rule=\"evenodd\" points=\"15 1.13 8.5 7.72 2 1.13\"></polyline></svg></span></button></h3><div data-core-height-transition-wrapper=\"\" class=\"r-height-transition-enter-done\" style=\"margin-top: 13.6px; overflow: visible; transition: height 0.3s ease-in-out;\"><div data-core-height-transition-content=\"\" style=\"overflow: visible;\"><div data-core-accordion-content=\"\" id=\"content-question-0\" style=\"transition: height 0.5s ease-in-out;\"><div class=\"rc-accordion-content large-10\" style=\"flex-basis: 83.3333%; max-width: 83.3333%; padding-bottom: 28px; font-size: 14px; letter-spacing: -0.016em; line-height: 1.42859; padding-inline-end: 35px;\">iPad Pro offers two anti-reflective glass options. Standard glass has an industry-leading anti‑reflective coating for viewing comfort and readability. Nano‑texture glass further minimises glare while delivering outstanding image quality in workspaces with bright light sources, like sunlight. Nano-texture glass is available in 1TB or 2TB configurations.</div><div class=\"rc-accordion-content large-10\" style=\"flex-basis: 83.3333%; max-width: 83.3333%; padding-bottom: 28px; font-size: 14px; letter-spacing: -0.016em; line-height: 1.42859; padding-inline-end: 35px;\"><ul data-core-accordion=\"\" id=\"question\" class=\"rc-accordion rf-faqsection-wrapper rc-accordion-compact\" role=\"list\" style=\"padding: 0px; margin-inline-start: 1.17647em; margin-right: 0px; margin-left: 0px; list-style: none; font-size: 17px; letter-spacing: -0.374px;\"><li data-core-accordion-item=\"\" class=\"rc-accordion-item\" role=\"listitem\" data-core-accordion-item-expanded=\"\" style=\"margin: 0px; padding: 0px; font-size: 1em; border-top: 1px solid rgb(210, 210, 215);\"><h3 style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(29, 29, 31); font-weight: 600;\"><button type=\"button\" data-core-accordion-button=\"\" aria-expanded=\"true\" aria-controls=\"content-question-1\" id=\"title-question-1\" class=\"rc-accordion-button\" data-core-accordion-button-expanded=\"\" style=\"padding: 17px 0px; background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; border-width: 0px; border-style: initial; border-color: initial; box-sizing: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: inherit; -webkit-font-smoothing: antialiased; font-synthesis: none; align-items: center; display: flex; width: 980px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0);\"><span class=\"rc-accordion-title large-10 typography-callout\" style=\"flex-basis: 83.3333%; max-width: 83.3333%; font-size: 17px; letter-spacing: -0.022em; line-height: 1.23536; text-align: start;\">Which Apple Pencil will work with my iPad?</span><span class=\"icon rc-accordion-collapse-icon\" style=\"margin-inline-start: auto;\"></span><span class=\"rc-accordion-chevrondown rc-accordion-collapse-icon\" style=\"align-items: flex-start; align-self: baseline; display: flex; justify-content: center; margin: 0px; transition: color 0.1s linear; width: 32px; stroke-width: 2.25; color: rgb(134, 134, 139); position: relative; margin-inline-start: auto;\"><svg class=\"accordion-icon-svg\" viewBox=\"0 0 17 8.85\" height=\"35px\" width=\"35px\"><polyline data-accordion-icon-shape=\"\" stroke=\"currentColor\" stroke-linecap=\"round\" stroke-linejoin=\"round\" fill=\"none\" fill-rule=\"evenodd\" points=\"15 1.13 8.5 7.72 2 1.13\"></polyline></svg></span></button></h3><div data-core-height-transition-wrapper=\"\" class=\"r-height-transition-enter-done\" style=\"margin-top: 13.6px; overflow: visible; transition: height 0.3s ease-in-out;\"><div data-core-height-transition-content=\"\" style=\"overflow: visible;\"><div data-core-accordion-content=\"\" id=\"content-question-1\" style=\"transition: height 0.5s ease-in-out;\"><div class=\"rc-accordion-content large-10\" style=\"flex-basis: 83.3333%; max-width: 83.3333%; padding-bottom: 28px; font-size: 14px; letter-spacing: -0.016em; line-height: 1.42859; padding-inline-end: 35px;\"><p style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px;\">Both Apple Pencil Pro and Apple Pencil (USB-C) are compatible with this iPad Pro.</p><p style=\"margin: 11.2px 0px 0px; padding: 0px;\">Apple Pencil Pro pairs wirelessly and attaches magnetically for charging and storage.</p><p style=\"margin: 11.2px 0px 0px; padding: 0px;\">Apple Pencil (USB-C) pairs via USB-C Charge Cable and attaches magnetically for storage.</p></div></div></div></div></li></ul></div></div></div></div></li></ul>', NULL, NULL, NULL, 700.00, 800.00, 1, 15, 7, '', 'sku-80', 'barcode-81', 'Yes', 5, 1, '2025-09-07 23:26:43', '2026-02-21 11:04:58');
