(81, 'Apple iPad Tablet 9.7 inch 16gb', 'apple-ipad-tablet-97-inch-16gb', '<p>Apple iPad Tablet 9.7 inch 16gb</p><h4 style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: 1.1; font-family: Arial, Helvetica, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; font-size: 17px; vertical-align: baseline; color: rgb(102, 102, 102); outline: 0px !important;\">DESCRIPTION:</h4><article style=\"margin: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: Arial, Helvetica, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; font-size: 13px; vertical-align: baseline; color: rgb(102, 102, 102); outline: 0px !important;\"><div id=\"description-full\" style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; outline: 0px !important;\"><div class=\"container columns\" style=\"margin-top: 0px; margin-bottom: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; max-width: 1170px; outline: 0px !important;\"><div class=\"row\" style=\"margin: 0px -10px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; outline: 0px !important;\"><div class=\"large-12 medium-12\" style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; outline: 0px !important;\"><p style=\"margin-right: 0px; margin-bottom: 1em; margin-left: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: 27px; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; font-size: 14px; vertical-align: baseline; min-height: 1px; color: rgb(101, 101, 101); outline: 0px !important;\">Apple iPad 2 is packed with powerful features in a slim body. Apple iPad 16GB is extremely user friendly and will keep you engaged for long stretches of hours.The Apple iPad 2 comes with iOS, which is an exclusive operating system invented by the brand. With a 9.7 inch screen and a widescreen, LED backlit display, this tablet from Apple surpasses all expectations. Equipped with modern features like Retina display and FaceTime calling, and a variety of built in applications, the iPad 2 makes operating your daily tasks a breeze. The Apple tablet is an effective combination of innovative technology and powerful features. The resolution of 1024 x 768 pixels at 132ppi boasts of clarity. The oleophobic coating keeps the screen crystal clear and resistant to fingerprints. The Apple iPad 2 uses a support for the display of multiple languages and characters simultaneously, and is designed to meet the modern standards of technology. It is powered by a rechargeable lithium polymer battery, which offers long hours of operation.</p></div></div></div></div></article>', 'Apple iPad Tablet 9.7 inch 16gb', NULL, '', 1000.00, 1200.00, 1, 15, 7, '', 'sku-81', 'barcode-81', 'Yes', 9, 1, '2025-09-07 23:29:01', '2026-02-26 11:44:05'),
(82, 'Dell Venue 11 Pro 7000 Series Windows 8.1 Tablet', 'dell-venue-11-pro-7000-series-windows-81-tablet', '<div class=\"product-condition\" style=\"box-sizing: inherit; color: rgb(102, 102, 102); font-family: Inter, sans-serif; font-size: 14px; letter-spacing: 0.5px; background-color: rgb(247, 247, 247);\"><label class=\"label\" style=\"box-sizing: inherit; touch-action: manipulation; color: rgb(0, 0, 0); text-align: right;\">Condition:</label>&nbsp;<span style=\"box-sizing: inherit;\">New</span></div><div class=\"product-information\" style=\"box-sizing: inherit; color: rgb(102, 102, 102); font-family: Inter, sans-serif; font-size: 14px; letter-spacing: 0.5px; background-color: rgb(247, 247, 247);\"><div id=\"product-description-short-737\" itemprop=\"description\" style=\"box-sizing: inherit;\"><ul style=\"box-sizing: inherit; list-style: none; padding-left: 0px;\"><li style=\"box-sizing: inherit;\">Intel Core Processor, 4GB 1600MHz Memory, 64GB SSD, Intel HD Graphics 5300</li><li style=\"box-sizing: inherit;\">10.8 inch wide angle Display (Full HD 1920 x 1080 resolution)</li><li style=\"box-sizing: inherit;\">Flexible three-in-one design (tablet, laptop &amp; desktop applications)</li><li style=\"box-sizing: inherit;\">Windows 8.1 tablet, WiFi + Bluetooth 4.0, USB 3.0, 10-pt capacitive touch screen</li><li style=\"box-sizing: inherit;\">Full-size mobile keyboard &amp; desktop docking station as accessories</li><li style=\"box-sizing: inherit;\">8mp (rear) &amp; 2mp (front) cameras</li><li style=\"box-sizing: inherit;\">SRS premium audio &amp; adaptive noise cancelling</li><li style=\"box-sizing: inherit;\">2 mics for video conferencing and soft phone</li><li style=\"box-sizing: inherit;\">Powerful and efficient Intel Core™ M processor</li><li style=\"box-sizing: inherit;\">Dell Data Protection|Encryption - perfect security</li><li style=\"box-sizing: inherit;\">Built-in Trusted Platform Module</li><li style=\"box-sizing: inherit;\">20GB of Dropbox space included for a year</li></ul></div></div>', 'Dell Venue 11 Pro 7000 Series Windows 8.1 Tablet', NULL, '', 150000.00, 200000.00, 1, 15, 4, '', 'sku-82', 'barcode-82', 'Yes', 0, 1, '2025-09-07 23:32:40', '2026-02-21 11:09:04'),
(83, 'Adorn India Blazer Plus Seater Sofa Set', 'adorn-india-blazer-plus-seater-sofa-set', '<p>Adorn India Blazer Plus 3+1+1 5 Seater Sofa Set</p>', 'Seater Sofa Set', NULL, '', 150000.00, NULL, 4, 19, 17, '', 'sku-83', 'barcode-83', 'Yes', 8, 1, '2025-09-07 23:41:34', '2026-02-26 12:49:23'),
